document.addEventListener('DOMContentLoaded', function () {
  const header = document.querySelector('header');
  
  
    //header.style.background =  
  header.style.background = 'transparent';
  // ✅ ENCÀPSULACIÓ: només s'executa 1 cop per sessió
  const KEY = 'sktIntroDone_v1';

  // SI JA S'HA FET L'ANIMACIÓ
  if (sessionStorage.getItem(KEY) === '1') {
    console.log('⚠️ Animació ja feta aquesta sessió. Mostrant estat final.');
    header.style.background = "#fffdf7";
    // 🔓 Assegurem que el scroll no està bloquejat
    document.body.classList.remove('scroll-locked');
    
    // 📌 Fixem el menú immediatament
    const menu = document.getElementById('skt-header');
    if (menu) {
      menu.classList.add('skt-menu--fixed');
    }
    
    // 🎯 Fem visible el logo del header immediatament
    const sktLogo = document.getElementById('sktLogo');
    if (sktLogo) {
      sktLogo.style.opacity = '1';
    }
    
    // 🖼️ Mostrem les feines (si existeix l'element)
    const works = document.querySelector('.skt-works');
    if (works) {
      works.style.opacity = '1';
    }
    
    // 🚫 Surt sense executar cap animació
    return;
  }

  // --- A PARTIR D'AQUÍ, EL TEU CODI ORIGINAL ---
  
  const headerEl = document.getElementById('sktLogo');

  const isMobile = window.innerWidth < 768;
  const logoHeight = 32; // La mida que tens al CSS

  // 1. DEFINIM LES VARIABLES PER DISPOSITIU
  const config = isMobile ? {
    // CONFIGURACIÓ MÒBIL
    logoWidthPercent: 0.90,
    topPosition: window.innerHeight / 2, // Centrat verticalment
    leftPosition: window.innerWidth / 2
  } : {
    // CONFIGURACIÓ DESKTOP
    logoWidthPercent: 0.95,
    topPosition: window.innerHeight - (logoHeight / 0.13),
    leftPosition: window.innerWidth / 2
  };

  if (!headerEl) return;

  // Creem el container per al logo d'intro
  const introEl = document.createElement('div');
  introEl.id = 'sktIntroLogo';
  document.body.prepend(introEl);

  // Bloquem scroll real
  document.body.classList.add('scroll-locked');

  // Carreguem Lottie al logo d'intro (instància separada)
  lottie.loadAnimation({
    container: introEl,
    renderer: 'svg',
    loop: true,
    autoplay: true,
    path: '/wp-content/themes/skt-theme/assets/json/logo-skt.json'
  });

  // Quan tot està pintat, calculem posicions
  setTimeout(() => {
    const headerRect = headerEl.getBoundingClientRect();
    const logoHeight = headerRect.height;

    // 2. APLIQUEM LES VARIABLES A L'OBJECTE START
    const start = {
      left: config.leftPosition,
      top: config.topPosition,
      width: window.innerWidth * config.logoWidthPercent
    };

    // Punt final: al centre del logo del header
    const end = {
      left: headerRect.left + headerRect.width / 2,
      top: headerRect.top + headerRect.height / 2,
      width: headerRect.width
    };

    // Scroll fals per simular efecte
    const maxScroll = Math.floor(window.innerHeight * 0.9);
    const fake = document.createElement('div');
    fake.style.height = `${maxScroll}px`;
    document.body.insertBefore(fake, introEl.nextSibling);

    // Posició inicial del logo d'intro
    introEl.style.left = `${start.left}px`;
    introEl.style.top = `${start.top}px`;
    introEl.style.width = `${start.width}px`;
    introEl.style.transform = 'translate(-50%, -50%)';

    // Animació en fer scroll
    window.addEventListener('scroll', function onScroll() {
      const works = document.querySelector('.skt-works');
      const scroll = Math.min(window.scrollY, maxScroll);
      const progress = scroll / maxScroll;

      const currentLeft = start.left + (end.left - start.left) * progress;
      const currentTop = start.top + (end.top - start.top) * progress;
      const currentWidth = start.width + (end.width - start.width) * progress;

      introEl.style.left = `${currentLeft}px`;
      introEl.style.top = `${currentTop}px`;
      introEl.style.width = `${currentWidth}px`;
      introEl.style.transform = 'translate(-50%, -50%)';
      
      // Això és important: mostrar les feines durant l'animació
      if (works) {
        works.style.opacity = '1';
        //works.style.opacity = easeOutCubic(progress).toFixed(3);
      }

      if (scroll >= maxScroll) {
        window.removeEventListener('scroll', onScroll);

        // ✅ MARQUEM COM EXECUTAT (per la següent càrrega)
        sessionStorage.setItem(KEY, '1');

        // 🔓 Desbloquegem scroll real
        document.body.classList.remove('scroll-locked');

        // 🔁 Tornem scrollTop a 0 forçat
        window.scrollTo(0, 0);

        // 📌 Fixem el menú
        const menu = document.getElementById('skt-header');
        const sktIntroLogo = document.getElementById('sktLogo');
        if (menu) {
          menu.classList.add('skt-menu--fixed');
        }

        introEl.remove();
        fake.remove();
        if (sktIntroLogo) {
    
          sktIntroLogo.style.opacity = '1';
          
          header.style.background = "#fffdf7";
        }
      }
    });
  }, 150);
});

function easeOutCubic(x) {
  return 1 - Math.pow(1 - x, 3);
}